import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, Grid } from '@mui/material';
import response from './response.json';

interface InventoryData {
  stockOverview: {
    totalItems: number;
    lowStockItems: number;
    reorderSuggestions: number;
  };
  lowStockItems: {
    item: string;
    currentStock: number;
    reorderLevel: number;
  }[];
  reorderSuggestions: {
    item: string;
    suggestedOrderQty: number;
  }[];
}

export default function Widget() {
  const inventoryData = response.data as InventoryData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Inventory Summary
            </Typography>
            <Typography variant="h6" fontWeight={700} sx={{ color: '#FF5722' }}>
              Total Items: {inventoryData.stockOverview.totalItems}
            </Typography>
            <Typography variant="body2" sx={{ color: '#FF5722' }}>
              Low Stock: {inventoryData.stockOverview.lowStockItems} | Reorder Suggestions: {inventoryData.stockOverview.reorderSuggestions}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Low Stock Items
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {inventoryData.lowStockItems.slice(0, 3).map((item, index) => (
                <Chip
                  key={index}
                  label={`${item.item} (${item.currentStock})`}
                  sx={{ fontSize: '11px', px: 1, py: 0.5 }}
                />
              ))}
            </Stack>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Reorder Suggestions
            </Typography>
            <Grid container spacing={1}>
              {inventoryData.reorderSuggestions.slice(0, 3).map((suggestion, index) => (
                <Grid item xs={4} key={index}>
                  <Chip
                    label={`${suggestion.item} (${suggestion.suggestedOrderQty})`}
                    sx={{ width: '100%', fontSize: '10px' }}
                  />
                </Grid>
              ))}
            </Grid>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
